337	                        if (pc >= 0) { io_print(" ["); print_int(pc + 1); putchar(93); pc = -1; }
338	                        putchar(10);
339	                    } else if (node_type[root] == NODE_ASSIGN) {
340	                        // Assignment: no output (APL convention)
341	                        // Don't restore heap -- variable value persists
342	                    } else if (node_type[root] == NODE_QLED_ASSIGN) {
343	                        // Quad LED assignment: no output
