381	                            // Find max width across all elements
382	                            int maxw = 1;
383	                            int j = 0;
384	                            while (j < sz) {
385	                                int w = num_width(arr_get(result, j));
386	                                if (w > maxw) maxw = w;
387	                                j++;
388	                            }
389	                            // Print each row on its own line
390	                            int r = 0;
391	                            while (r < rows) {
392	                                int c = 0;
393	                                while (c < cols) {
394	                                    if (c == 0) putchar(32);
