396	                                    if (c + 1 < cols) putchar(32);
397	                                    c++;
398	                                }
399	                                putchar(10);
400	                                r++;
401	                            }
402	                        }
403	                        // Reclaim temporaries
404	                        heap_top = heap_save;
405	                    }
406	                }
407	            }
408	        }
