                int any = 0;
                while (i < fn_count) {
                    int sym = fn_name_sym[i];
                    if (any) io_print("  ");
                    int off = sym_name_off[sym];
                    while (sym_name_buf[off]) {
                        putchar(sym_name_buf[off]);
