                int after = di + 3;
                while (exec_line[after] == 32) after++;
                if (exec_line[after] == 0) {
                    // Bare "del" outside definition mode
                    io_print("  SYNTAX ERROR");
                    if (pc >= 0) { io_print(" ["); print_int(pc + 1); putchar(93); pc = -1; }
                    putchar(10);
                } else if (pc >= 0) {
