                    io_print("  SYNTAX ERROR");
                    io_print(" ["); print_int(pc + 1); putchar(93); pc = -1;
                    putchar(10);
                } else {
                    // Start function definition
                    int temp = fn_count;
                    if (temp >= FN_MAX) {
                        io_print("  FN TABLE FULL");
                        putchar(10);
                    } else if (!parse_fn_header(exec_line + after, temp)) {
                        io_print("  SYNTAX ERROR");
                        putchar(10);
                    } else {
